local _reportIdx = 0
local function MakeReportIndex()
    local idx = _reportIdx + 1
    if idx > 2147483647 then
        idx = 1
    end
    _reportIdx = idx
    return idx
end

---@class LFightReportData
local LFightReportData = classX("LFightReportData", nil)
function LFightReportData:ctor(reportId)
    self._index = MakeReportIndex()
    ---@type string
    self.id = reportId or ""

    ---@type LFightFormationData 进攻方
    self.formationA = nil
    ---@type LFightFormationData 防守方
    self.formationB = nil

    ---@type LFightDetailsData
    self.details = nil

    --- 1-A胜利，2-B胜利
    ---@type number
    self.winner = 0

    ---@type number 战斗类型(玩法)
    self.combatType = 0
    self.battleType = 0

    ---@type LFightRoundData[] 回合数据集合
    self.rounds = nil

    ---@type number 进攻方serverId
    self.serverIdA = 0
    ---@type number 防守方serverId
    self.serverIdB = 0

    ---@type number 最大回合
    self.maxRound = 0
    ---@type number 宝物系统 标识  0=不支持宝物 1=支持宝物 注意：主角不受影响
    self.treasure = 0
    --- 初始显示数据（json格式）
    --- {
    --- ```
    --- type;// 1伤害倍数
    --- damageMultiple;//伤害倍数值
    --- bossId;//bossId比如用来显示头像
    ---```
    --- }
    ---@type string
    self.initShowJson = nil


    ---@type boolean
    self._isDisposed = false

    self.totalRound = 0

    self.isReportEnd = false
    self.isReportInit = false

    ---combatResp 内容
    ---@type int64 -> number 战斗开始时间
    self.startTime = 0
    ---@type string
    self.targetName = nil
    ---@type number
    self.targetLevel = nil
    ---@type number 防守方为怪物是monsterId
    self.monsterId = nil
    ---@type number 跨服字段： 战报所在服务器Id
    self.serverId = nil
    ---@type number 可选字段 怪物配置Id
    self.refId = nil
    ---@type number 怪物加成Id
    self.addCostId = nil
    ---@type string 额外的战报
    self.multReportIds = nil
    ---@type string 活动数据，部分战斗活动可能已经结束了，但是又需要活动数据（客户端自己拼格式，服务端只做记录转发）
    self.activityData = nil
    ---combatResultResp 内容
    ---@type LBattleResultData
    self.battleResultData = nil

    self.isReportCreateFinished = false

    ---@type number 当前回合数
    self._curRoundIdx = 0

    ---@type LxItemInfo|LxHeroInfo|LxEquipInfo
    self.reward = nil

    self.isNeedRemoveInResult = false
end

function LFightReportData:ToJsonTable()
    local reportJson = {}
    reportJson.id = self.id
    reportJson.formationA = self.formationA:ToJsonTable()
    reportJson.formationB = self.formationB:ToJsonTable()
    reportJson.details = self.details:ToJsonTable()
    reportJson.winner = self.winner
    reportJson.combatType =  self.combatType


    reportJson.rounds = {}
    for i, v in ipairs(self.rounds) do
        table.insert(reportJson.rounds, v:ToJsonTable())
    end

    reportJson.serverIdA =  self.serverIdA
    reportJson.serverIdB =  self.serverIdB
    reportJson.maxRound =  self.maxRound
    reportJson.treasure =  self.treasure
    reportJson.initShowJson =  self.initShowJson and CJSON.encode(self.initShowJson)

    return reportJson
end

function LFightReportData:AttachProcess(process)
    ---@type LBattleProcess
    self.attachProcess = process
end
function LFightReportData:InitFromCombatResp(pb)
    self.combatType = pb.combatType
    self.battleType = pb.combatType
    self.startTime = tonumber(pb.startTime)
    self.targetName = pb.targetName
    self.targetLevel = pb.targetLevel
    self.monsterId = pb.monsterId
    self.serverId = pb.serverId
    self.refId = pb.refId
    self.addCostId = pb.addCostId
    self.multReportIds = pb.multReportIds
    self.activityData = pb.activityData
end

function LFightReportData:SetBattleResult(pb)
    self.battleResultData = self:NewResultData(pb)
end

-- 从完整的战报初始化
function LFightReportData:InitData(fullData)
    self.isReportInit = true

    self.innerId = fullData.id
    self.formationA = self:NewTeamData(fullData.formationA, BattleTeamSide.teamA)
    self.formationB = self:NewTeamData(fullData.formationB, BattleTeamSide.teamB)
    self.details = self:NewDetails(fullData.details)
    self.winner = fullData.winner
    self.combatType = fullData.combatType
    self.battleType = fullData.combatType

    local lifeState = {}

    local rounds = {}
    self.rounds = rounds
    ---@type LFightRoundData
    local roundItem = nil
    for idx,round in ipairs(fullData.rounds) do
        roundItem = self:NewRoundData(round, lifeState)
        table.insert(rounds, roundItem)
    end

    self.totalRound = #rounds

    self.serverIdA =  fullData.serverIdA
    self.serverIdB =  fullData.serverIdB

    self.maxRound = fullData.maxRound
    self.treasure =  fullData.treasure

    self:SetInitShowJson(fullData.initShowJson)

    self.isReportEnd = true

    self.lifeState = lifeState

    if ENABLE_FIGHT_LOG then
        if LxAppHelper.IsEditor() then
            self:SaveToLocal()
        end
    end
end

function LFightReportData:Dispose()
    if self._isDisposed then
        return
    end

    table.dispose(self)
    self._isDisposed = true
end

function LFightReportData:IsDisposed()
    return self._isDisposed
end

function LFightReportData:Reset()
    self._state = BattleState.Battle
    self._curRoundIdx = 1
end

---@return LBattleHeroSpeedData
function LFightReportData:GetNextHeroData()
    local roundIdx = self._curRoundIdx

    ---@type LBattleHeroSpeedData
    local findHeroSpeed = nil

    if self._roundCdList then
        for skillId, heroSpeedData in pairs(self._roundCdList) do
            if heroSpeedData:IsNextHero(roundIdx) and (not findHeroSpeed or findHeroSpeed.speed < heroSpeedData.speed) then
                findHeroSpeed = heroSpeedData
            end
        end
    end

    return findHeroSpeed
end

---@return LBattleHeroSpeedData
function LFightReportData:GetRoleSkillData(teamIdx)
    ---@type LFightFormationData
    local formation = self.formationA
    if teamIdx == BattleTeamSide.teamB then
        formation = self.formationB
    end
    ---@type LBattleUnitGridData
    local roleGridData = nil
    for i, v in pairs(formation.grids) do
        if v.index > 6 then
            roleGridData = v
            break
        end
    end
    if not roleGridData then
        return nil
    end
    ---@type LBattleHeroSpeedData
    local roleSpeedData = nil
    if self._roundCdList then
        for i, heroSpeedData in pairs(self._roundCdList) do
            if heroSpeedData.id == roleGridData.id then
                roleSpeedData = heroSpeedData
                break
            end
        end
    end

    return roleSpeedData
end

