end

function LFightReportData:HasRound(roundIdx)
    if not self.isReportInit then
        return false
    else
        local round = self:GetRound(roundIdx)
        return round ~= nil
    end
end

function LFightReportData:SaveToLocal()
    if string.isempty(self.id) then
        return
    end

    local jsonTab = self:ToJsonTable()
    local jsonStr = CJSON.encode(jsonTab)

    local fileName = self.id..".json"
    local savePath = LxPathHelper.AppPersistentDataPath .."/Report/"..fileName
    LFileHelper.WriteAllText(savePath, jsonStr, false)
end


function LFightReportData:SetInitShowJson(initShowJson)
    -- 初始显示数据（json格式）
    if string.isvalid(initShowJson) then
        self.initShowJson = CJSON.decode(initShowJson)
    end
end

