---@param formation LFightFormationData
function LFightReportData:GetFormationName(formation)
    local name = formation.formationName

    if self.battleType == BattleType.Video then
        if not string.isempty(name) then
            --- 本地录像直接使用
            return name
        end
    end

    local isMonster = formation.monster
    if isMonster then
        if not string.isempty(name) then
            return I18nText(name)
        end
        local monsterFormationRefId = formation.monsterFormationRefId
        if monsterFormationRefId and monsterFormationRefId > 0 then
            name = LxDataHelper.GetMonsterStationName(monsterFormationRefId)
        end
    else
        if self.battleType == BattleType.Test then
            name = ModuleCenter.Role:GetRoleName()
        else
            if string.isempty(name) then
                if formation.playerId == ModuleCenter.Role:GetRoleId() then
                    name = ModuleCenter.Role:GetRoleName()
                end
            end
        end
    end
    return name
end
------------------------ 获取战斗主角名字 end

